boolean isPrime(int n){
  if(n<2) return false;
  for(int i=2;i*i<=n;i++){
    if(n%i==0) return false;
  }
  return true;
}

Node reverse(Node head){
  Node prev=null, curr=head;
  while(curr!=null){
    Node next=curr.next;
    curr.next=prev;
    prev=curr;
    curr=next;
  }
  return prev;
}

